import json
import os
import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_SUBJECT = os.environ.get("DEFAULT_SUBJECT", "Event Notification")


def _response(status_code, body):
    return {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json"
        },
        "body": json.dumps(body)
    }


def _publish_to_sns(topic_arn, message, subject=None, message_attributes=None):
    params = {
        "TopicArn": topic_arn,
        "Message": message if isinstance(message, str) else json.dumps(message),
    }

    if subject:
        params["Subject"] = subject

    if message_attributes:
        params["MessageAttributes"] = message_attributes

    return sns.publish(**params)


def _build_message(event):
    notification_type = event.get("notification_type", "default")
    content = event.get("message", event.get("content", ""))
    data = event.get("data", {})

    if notification_type == "default":
        message = content
        subject = event.get("subject", DEFAULT_SUBJECT)
    elif notification_type == "json":
        message = {
            "notification_type": notification_type,
            "message": content,
            "data": data,
        }
        subject = event.get("subject", DEFAULT_SUBJECT)
    elif notification_type == "alert":
        message = {
            "type": "alert",
            "message": content,
            "severity": event.get("severity", "high"),
            "data": data,
        }
        subject = event.get("subject", "ALERT")
    elif notification_type == "status":
        message = {
            "type": "status",
            "message": content,
            "status": event.get("status", "unknown"),
            "data": data,
        }
        subject = event.get("subject", "Status Update")
    else:
        message = {
            "notification_type": notification_type,
            "message": content,
            "data": data,
        }
        subject = event.get("subject", DEFAULT_SUBJECT)

    return message, subject


def lambda_handler(event, context):
    try:
        topic_arn = event.get("topic_arn") or event.get("TopicArn")
        if not topic_arn:
            return _response(400, {"error": "Missing required field: topic_arn"})

        message, subject = _build_message(event)

        message_attributes = event.get("message_attributes")
        if message_attributes and not isinstance(message_attributes, dict):
            return _response(400, {"error": "message_attributes must be a dictionary"})

        publish_result = _publish_to_sns(
            topic_arn=topic_arn,
            message=message,
            subject=subject,
            message_attributes=message_attributes,
        )

        return _response(200, {
            "status": "published",
            "message_id": publish_result.get("MessageId"),
            "topic_arn": topic_arn,
        })

    except ClientError as e:
        return _response(500, {
            "error": "SNS publish failed",
            "details": e.response.get("Error", {}),
        })
    except Exception as e:
        return _response(500, {
            "error": "Unexpected error",
            "details": str(e),
        })